<script setup lang="ts">import{computed,ref}from'vue';import{onPullDownRefresh,onShow}from'@dcloudio/uni-app';import{getMobileAuditLogs}from'@/api/business';import type{OperationLog}from'@/types/business';const rows=ref<OperationLog[]>([]),error=ref(''),keyword=ref('');const filteredRows=computed(()=>{const text=keyword.value.trim().toLowerCase();return!text?rows.value:rows.value.filter(row=>[row.operatorName,row.action,row.targetType,row.targetId,row.reason].some(value=>String(value||'').toLowerCase().includes(text)))});async function load(){try{error.value='';rows.value=await getMobileAuditLogs()}catch(e){error.value=e instanceof Error?e.message:'日志加载失败'}}onShow(load);onPullDownRefresh(async()=>{await load();uni.stopPullDownRefresh()})</script>
<template><view class="page"><view class="head"><text class="title">操作日志</text><button @click="load">刷新</button></view><input v-model="keyword" class="search" placeholder="搜索操作人、动作、业务对象或原因"/><view v-if="error" class="state">{{error}}</view><view v-if="!filteredRows.length&&!error" class="state">没有匹配的操作日志</view><view v-for="r in filteredRows" :key="r.id" class="card"><text class="name">{{r.operatorName||'系统'}} · {{r.action}}</text><text class="copy">{{r.targetType||'业务'}} {{r.targetId||''}}</text><text class="copy">{{r.reason||'—'}} · {{r.createdAt||'—'}}</text></view></view></template><style scoped lang="scss">.page{min-height:100vh;padding:24rpx;background:#f2f6f5}.head{display:flex;align-items:center;justify-content:space-between}.title{font-size:40rpx;font-weight:750}.head button{margin:0;background:#fff;color:#1f5752}.search{box-sizing:border-box;width:100%;margin-top:18rpx;padding:20rpx;background:#fff;border-radius:14rpx}.card,.state{margin-top:16rpx;padding:24rpx;background:#fff;border-radius:16rpx}.name,.copy{display:block}.name{font-weight:700}.copy{margin-top:8rpx;color:#71807d;font-size:23rpx}.state{text-align:center;color:#71807d}</style>
